const BASE_TIMESTAMP = 1741046400000;
const MS_PER_SLOT = 6 * 60 * 60 * 1000;
const now = Date.now();

// Soporte para override desde webhook de test (?slot=N)
const triggerInput = $input.first().json;
const slotOverride = triggerInput.query?.slot ?? triggerInput.body?.slot;
const slotIndex = slotOverride !== undefined && slotOverride !== ''
  ? parseInt(slotOverride)
  : Math.floor((now - BASE_TIMESTAMP) / MS_PER_SLOT);

const dayOfWeek = new Date(now).getDay();
return [{ json: { slotIndex, dayOfWeek, now } }];

const slotData = $('Calcular Slot Temporal').first().json;
const slotIndex = slotData.slotIndex;
const dayOfWeek = slotData.dayOfWeek;
const sanityResult = $input.first().json.result || [];

const SECTORS = [
  'inmobiliarias y agencias inmobiliarias',
  'clinicas medicas y dentales',
  'restaurantes y hosteleria',
  'talleres mecanicos',
  'concesionarios de automoviles',
  'despachos de abogados',
  'academias y centros de formacion',
  'empresas de logistica y transporte',
  'aseguradoras y corredurias de seguros',
  'comercio retail y tiendas',
  'clinicas veterinarias',
  'centros de fisioterapia y rehabilitacion',
  'asesorias y gestorias',
  'agencias de marketing digital',
  'empresas de construccion y reformas',
  'centros de estetica y peluquerias',
  'consultorios psicologicos',
  'promotoras inmobiliarias',
  'empresas de seguridad y vigilancia',
  'farmacias y parafarmacias',
  'hoteles y apartamentos turisticos',
  'agencias de viajes',
  'gimnasios y centros deportivos',
  'clinicas de fertilidad y medicina estetica',
  'instaladores de energia solar',
  'empresas de limpieza profesional',
  'distribuidores mayoristas',
  'estudios de arquitectura e ingenieria',
  'empresas de reclutamiento y RRHH',
  'startups tecnologicas espanolas'
];

const HOW_TO_TOPICS = [
  { topic: 'como implementar un chatbot en WhatsApp Business', tool: 'n8n + OpenAI' },
  { topic: 'como automatizar respuestas a emails de clientes', tool: 'n8n + Gmail' },
  { topic: 'como conectar tu CRM con WhatsApp y email', tool: 'n8n + HubSpot' },
  { topic: 'como crear un agente de voz que gestione citas', tool: 'ElevenLabs + n8n' },
  { topic: 'como automatizar informes semanales con IA', tool: 'n8n + GPT-4' },
  { topic: 'como integrar Holded con cualquier herramienta', tool: 'n8n' },
  { topic: 'como usar IA para clasificar leads automaticamente', tool: 'n8n + OpenAI' },
  { topic: 'como montar un pipeline de ventas automatizado', tool: 'n8n + CRM' },
  { topic: 'guia de n8n para pymes primeros pasos', tool: 'n8n' },
  { topic: 'como automatizar facturas y albaranes', tool: 'n8n + Holded' },
  { topic: 'como crear un sistema de seguimiento de pedidos', tool: 'n8n + WhatsApp' },
  { topic: 'como conectar Calendly con tu CRM automaticamente', tool: 'n8n' },
  { topic: 'como implementar un chatbot multiidioma para turismo', tool: 'n8n + OpenAI' },
  { topic: 'como medir el ROI real de la automatizacion', tool: 'metodologia' },
  { topic: 'como hacer scraping legal para inteligencia de mercado', tool: 'n8n + Apify' }
];

const NEWS_TOPICS = [
  'GPT-4o y modelos de voz en tiempo real que cambia para las pymes',
  'La normativa europea de IA AI Act y como afecta a tu empresa en Espana',
  'Agentes autonomos de IA que son y cuando estaran listos para pymes',
  'Modelos pequenos SLM alternativas a GPT para pymes con presupuesto',
  'Automatizacion con IA vs RPA clasico cual elegir en 2025',
  'IA generativa en atencion al cliente estado actual en el mercado espanol',
  'El impacto de los voice bots en la hosteleria espanola',
  'Como estan adoptando la IA las pymes valencianas datos y tendencias',
  'OpenAI Anthropic Google que modelo es mejor para automatizacion de negocio',
  'El futuro del trabajo en Espana que tareas automatizara la IA antes de 2027'
];

const ROI_TOPICS = [
  { sector: 'clinicas medicas', metric: 'coste por cita no presentada vs chatbot de recordatorios' },
  { sector: 'restaurantes', metric: 'ROI de automatizar reservas vs recepcionista nocturno' },
  { sector: 'despachos de abogados', metric: 'horas facturables recuperadas con automatizacion documental' },
  { sector: 'talleres mecanicos', metric: 'ingresos perdidos por llamadas no atendidas' },
  { sector: 'academias', metric: 'coste de gestion de matriculas manual vs automatizado' },
  { sector: 'retail', metric: 'impacto de respuesta 24/7 en conversion de ecommerce' },
  { sector: 'logistica', metric: 'reduccion de incidencias con seguimiento automatico' },
  { sector: 'inmobiliarias', metric: 'coste de cualificacion de leads sin IA' }
];

const COMPARATIVE_TOPICS = [
  'n8n vs Zapier vs Make cual elegir para una pyme espanola',
  'Chatbot de reglas vs chatbot con IA diferencias reales de coste y calidad',
  'Agente de voz vs formulario web cual convierte mas en el sector sanitario',
  'HubSpot vs Salesforce vs Holded CRM para pymes con automatizacion',
  'GPT-4.1 vs Claude vs Gemini para redaccion comercial en espanol',
  'WhatsApp Business API vs chatbot web pros y contras para pymes'
];

const CATEGORY_BY_TYPE = {
  SECTOR_USECASE:  ['Casos de Uso', 'Automatización', 'Chatbots', 'Agentes de Voz', 'Integraciones'],
  HOW_TO:          ['Automatización', 'Integraciones', 'Chatbots'],
  AI_NEWS_APPLIED: ['Noticias IA', 'Automatización'],
  ROI_BUSINESS:    ['Casos de Uso', 'Automatización'],
  COMPARATIVE:     ['Integraciones', 'Automatización', 'Noticias IA']
};

const HOOK_DESCRIPTIONS = {
  A: 'Pregunta directa al problema real del lector',
  B: 'Dato o estadistica especifica del sector en Espana',
  C: 'Escenario concreto y vivido (narrativo)',
  D: 'Comparativa antes/despues sin IA vs con IA',
  E: 'Objecion tipica del sector desmontada',
  F: 'Coste real de no automatizar, calculado para el sector',
  G: 'Historia breve de empresa anonimizada en ciudad valenciana',
  H: 'Tendencia del mercado + aplicacion practica al sector en Espana'
};

const recentPosts = sanityResult.slice(0, 30);
const sectorCount = {};
const categoryCount = {};
for (const post of recentPosts) {
  if (post.sector) sectorCount[post.sector] = (sectorCount[post.sector] || 0) + 1;
  if (post.category) categoryCount[post.category] = (categoryCount[post.category] || 0) + 1;
}

const typeKeys = [
  'SECTOR_USECASE','SECTOR_USECASE','SECTOR_USECASE','SECTOR_USECASE',
  'SECTOR_USECASE','SECTOR_USECASE','SECTOR_USECASE','SECTOR_USECASE',
  'HOW_TO','HOW_TO','HOW_TO','HOW_TO','HOW_TO',
  'AI_NEWS_APPLIED','AI_NEWS_APPLIED','AI_NEWS_APPLIED','AI_NEWS_APPLIED',
  'ROI_BUSINESS','ROI_BUSINESS',
  'COMPARATIVE'
];

let contentType = typeKeys[slotIndex % typeKeys.length];
if ((dayOfWeek === 1 || dayOfWeek === 5) && slotIndex % 3 === 0) {
  contentType = 'AI_NEWS_APPLIED';
}

let topicConfig = {};
if (contentType === 'SECTOR_USECASE') {
  const EXCLUSION_WINDOW = 8;
  const recentSectors = recentPosts.slice(0, EXCLUSION_WINDOW).map(p => p.sector).filter(Boolean);
  const available = SECTORS.filter(s => !recentSectors.includes(s));
  const pool = available.length > 0 ? available : SECTORS;
  const sorted = pool.slice().sort((a, b) => (sectorCount[a] || 0) - (sectorCount[b] || 0));
  const candidates = sorted.slice(0, Math.ceil(sorted.length / 2));
  topicConfig = { sector: candidates[slotIndex % candidates.length] };
} else if (contentType === 'HOW_TO') {
  topicConfig = HOW_TO_TOPICS[slotIndex % HOW_TO_TOPICS.length];
} else if (contentType === 'AI_NEWS_APPLIED') {
  topicConfig = { topic: NEWS_TOPICS[slotIndex % NEWS_TOPICS.length] };
} else if (contentType === 'ROI_BUSINESS') {
  topicConfig = ROI_TOPICS[slotIndex % ROI_TOPICS.length];
} else if (contentType === 'COMPARATIVE') {
  topicConfig = { topic: COMPARATIVE_TOPICS[slotIndex % COMPARATIVE_TOPICS.length] };
}

const eligible = (CATEGORY_BY_TYPE[contentType] || ['Automatización']).slice()
  .sort((a, b) => (categoryCount[a] || 0) - (categoryCount[b] || 0));
let category = eligible[slotIndex % eligible.length];

if (contentType === 'SECTOR_USECASE' && topicConfig.sector) {
  const recentPairs = new Set(recentPosts.slice(0, 20).map(p => p.sector + '||' + p.category));
  if (recentPairs.has(topicConfig.sector + '||' + category)) {
    const altCats = eligible.filter(c => !recentPairs.has(topicConfig.sector + '||' + c));
    if (altCats.length > 0) category = altCats[0];
  }
}

const AUTHORS = ['Pablo Álvarez', 'Marc Balaguer', 'Pau Balaguer'];
const author = AUTHORS[slotIndex % AUTHORS.length];

const HOOKS = ['A', 'B', 'C', 'D', 'E', 'F', 'G', 'H'];
const hook = HOOKS[(slotIndex + 3) % HOOKS.length];
const hookDesc = HOOK_DESCRIPTIONS[hook];

const recentContext = recentPosts.slice(0, 15).map(p => {
  let line = '[' + (p.category || '?') + '] ' + (p.title || '?');
  if (p.excerpt) line += ' — ' + p.excerpt.substring(0, 80);
  if (p.angle) line += ' | Angulo: ' + String(p.angle).substring(0, 100);
  return line;
}).join('\n');

let topicDescription = '';
if (contentType === 'SECTOR_USECASE') {
  topicDescription = 'Sector objetivo: ' + topicConfig.sector;
} else if (contentType === 'HOW_TO') {
  topicDescription = 'Tutorial: "' + topicConfig.topic + '" con herramienta: ' + topicConfig.tool;
} else if (contentType === 'AI_NEWS_APPLIED') {
  topicDescription = 'Tendencia/noticia: ' + topicConfig.topic;
} else if (contentType === 'ROI_BUSINESS') {
  topicDescription = 'Analisis ROI — Sector: ' + topicConfig.sector + ' | Metrica: ' + topicConfig.metric;
} else if (contentType === 'COMPARATIVE') {
  topicDescription = 'Comparativa: ' + topicConfig.topic;
}

const plannerPrompt = 'Eres un estratega de contenido senior para el blog de Intelite AI (https://inteliteai.com), empresa de automatizacion con IA para pymes espanolas en San Juan de Alicante.\n\nASIGNACION PARA ESTE POST:\n- Tipo de contenido: ' + contentType + '\n- ' + topicDescription + '\n- Categoria del blog: ' + category + '\n- Hook de apertura a usar: Tipo ' + hook + ' — ' + hookDesc + '\n- Autor: ' + author + '\n\nPOSTS RECIENTES (NO repetir estos angulos ni argumentos):\n' + (recentContext || 'Ningun post publicado aun.') + '\n\nGenera un BRIEF estructurado de 150-180 palabras con exactamente estos 8 puntos numerados:\n1. ANGULO: El angulo diferenciador vs posts anteriores (1-2 frases)\n2. PRIMERA FRASE: La primera frase exacta del post (el hook aplicado)\n3. ARGUMENTOS: 3-4 argumentos principales unicos para este post\n4. DATO: Un dato o estadistica especifica a incluir (aproximada pero creible)\n5. FORMATO: Tipo de estructura (guia paso a paso / caso narrativo / comparativa / analisis ROI / checklist / tutorial)\n6. ELEMENTO VISUAL: Un elemento concreto (tabla / checklist / timeline / comparativa dos columnas)\n7. CTA: Call-to-action especifico y natural para este tipo de contenido\n8. KEYWORD_PRINCIPAL: La keyword SEO en 3-5 palabras (en espanol, sin tildes, como en Google)\n\nDevuelve UNICAMENTE JSON valido con dos campos: "mainKeyword" (string) y "brief" (string con los 8 puntos).';

return [{ json: { slotIndex, contentType, topicConfig, category, author, hook, hookDescription: hookDesc, recentContext, plannerPrompt, topicDescription } }];

const plannerOutput = $input.first().json.output || '';
const selectorData = $('Seleccionar Tema Inteligente').first().json;

let mainKeyword = '';
let brief = '';

const jsonMatch = plannerOutput.match(/\{[\s\S]*\}/);
if (jsonMatch) {
  try {
    const parsed = JSON.parse(jsonMatch[0]);
    mainKeyword = parsed.mainKeyword || '';
    brief = parsed.brief || plannerOutput;
  } catch (e) {
    brief = plannerOutput;
  }
} else {
  brief = plannerOutput;
}

const today = new Date().toISOString().substring(0, 10);
const writerPrompt = 'BRIEF DE CONTENIDO (sigue estas instrucciones al pie de la letra):\n' + brief + '\n\nPARAMETROS FIJOS (NO cambies estos valores en el JSON de salida):\n- Autor: ' + selectorData.author + '\n- Categoria: ' + selectorData.category + '\n- Fecha de publicacion: ' + today + '\n- Tipo de post: ' + selectorData.contentType + '\n\nCONTEXTO DE SATURACION (angulos ya cubiertos — NO repitas estas aperturas ni argumentos):\n' + (selectorData.recentContext || 'Ningun post publicado aun.') + '\n\nDevuelve unicamente el JSON valido del post completo.';

return [{ json: { ...selectorData, mainKeyword, brief, writerPrompt } }];

const raw = $input.first().json.output || '';
const promptData = $('Preparar Prompt del Escritor').first().json;

const jsonMatch = raw.match(/\{[\s\S]*\}/);
if (!jsonMatch) throw new Error('No JSON encontrado en la respuesta del writer. Inicio: ' + raw.substring(0, 300));

let post;
try {
  post = JSON.parse(jsonMatch[0]);
} catch (e) {
  throw new Error('JSON invalido del writer: ' + e.message + ' | Raw: ' + raw.substring(0, 200));
}

const required = ['title', 'slug', 'excerpt', 'markdownContent', 'category'];
for (const f of required) {
  if (!post[f]) throw new Error('Campo faltante en JSON del writer: ' + f);
}

const validCategories = ['Automatización', 'Agentes de Voz', 'Chatbots', 'Integraciones', 'Casos de Uso', 'Noticias IA'];
if (!validCategories.includes(post.category)) {
  throw new Error('Categoria invalida: ' + post.category + '. Validas: ' + validCategories.join(', '));
}

let schemaOrg = null;
const schemaMatch = post.markdownContent.match(/<!--\s*SCHEMA_ORG([\s\S]*?)-->/);
if (schemaMatch) {
  try {
    schemaOrg = JSON.parse(schemaMatch[1].trim());
    const h3Regex = /^###\s+(.+)$/gm;
    const h3Matches = [...post.markdownContent.matchAll(h3Regex)].map(m => m[1].trim());
    if (schemaOrg['@graph'] && h3Matches.length > 0) {
      const faqNode = schemaOrg['@graph'].find(n => n['@type'] === 'FAQPage');
      if (faqNode && faqNode.mainEntity) {
        faqNode.mainEntity = faqNode.mainEntity.map((q, i) => ({ ...q, name: h3Matches[i] || q.name }));
      }
    }
  } catch (e) {
    console.warn('Schema.org malformado: ' + e.message);
  }
}

post.coverImageKeywords = post.coverImageKeywords || 'professional business technology office Spain';
post.angle = post.angle || '';
post.mainKeyword = promptData.mainKeyword || '';

return [{ json: { ...post, schemaOrg } }];

const post = $input.first().json;
const mainKeyword = post.mainKeyword || '';
const hardIssues = [];
const softWarnings = [];

const VALID_CATEGORIES = ['Automatización', 'Agentes de Voz', 'Chatbots', 'Integraciones', 'Casos de Uso', 'Noticias IA'];

const requiredFields = ['title', 'slug', 'excerpt', 'markdownContent', 'category', 'author'];
for (const f of requiredFields) {
  if (!post[f] || String(post[f]).trim().length === 0) hardIssues.push('MISSING_FIELD: ' + f);
}

if (!VALID_CATEGORIES.includes(post.category)) hardIssues.push('INVALID_CATEGORY: ' + post.category);

const wordCount = (post.markdownContent || '').split(/\s+/).filter(w => w.length > 0).length;
if (wordCount < 900) hardIssues.push('WORD_COUNT_LOW: ' + wordCount + ' palabras (minimo 900)');

const forbiddenOpeners = ['descubre como', 'en el mundo actual', 'la inteligencia artificial esta transformando', 'en un entorno cada vez mas', 'en la era digital'];
const openingText = (post.markdownContent || '').substring(0, 400).toLowerCase();
for (const phrase of forbiddenOpeners) {
  if (openingText.includes(phrase)) hardIssues.push('FORBIDDEN_OPENER: "' + phrase + '"');
}

const h2Count = (post.markdownContent || '').match(/^## /gm)?.length || 0;
if (h2Count < 3) hardIssues.push('TOO_FEW_H2: solo ' + h2Count + ' secciones (minimo 3)');

const titleLen = (post.title || '').length;
if (titleLen < 30) softWarnings.push('TITLE_SHORT: ' + titleLen + ' chars');
if (titleLen > 80) softWarnings.push('TITLE_LONG: ' + titleLen + ' chars');

const excerptLen = (post.excerpt || '').length;
if (excerptLen < 100) softWarnings.push('EXCERPT_SHORT: ' + excerptLen + ' chars');
if (excerptLen > 200) softWarnings.push('EXCERPT_LONG: ' + excerptLen + ' chars');

const excerptLower = (post.excerpt || '').toLowerCase();
if (excerptLower.startsWith('descubre como') || excerptLower.startsWith('descubre c')) {
  softWarnings.push('EXCERPT_FORBIDDEN_OPENER');
}

if (!(post.markdownContent || '').includes('](/')) softWarnings.push('NO_INTERNAL_LINKS');

if (mainKeyword) {
  const firstWords = (post.title || '').split(' ').slice(0, 6).join(' ').toLowerCase();
  if (!firstWords.includes(mainKeyword.toLowerCase())) {
    softWarnings.push('KEYWORD_NOT_IN_TITLE_START: "' + mainKeyword + '" no en primeras 6 palabras');
  }
}

if (!post.schemaOrg) softWarnings.push('SCHEMA_ORG_MISSING: no se encontro bloque Schema.org en el markdown');

if (softWarnings.length > 0) console.log('[QUALITY WARNINGS] ' + (post.slug || '?') + ': ' + softWarnings.join(' | '));

const qualityPassed = hardIssues.length === 0 ? 'yes' : 'no';
return [{ json: { ...post, qualityPassed, qualityIssues: hardIssues, softWarnings, wordCount } }];

const post = $input.first().json;
console.warn('[QUALITY GATE FAIL] Post omitido: "' + (post.title || 'sin titulo') + '"');
console.warn('[ISSUES] ' + JSON.stringify(post.qualityIssues));
return [{ json: { skipped: true, reason: 'quality_gate_failed', issues: post.qualityIssues, title: post.title, slug: post.slug } }];

const pexelsResponse = $input.first().json;
const postData = $('Parsear JSON del Agente').first().json;

const FALLBACK_IMAGES = {
  'Automatización': 'https://images.unsplash.com/photo-1518770660439-4636190af475?w=1200&auto=format&fit=crop',
  'Chatbots': 'https://images.unsplash.com/photo-1587560699334-cc4ff634909a?w=1200&auto=format&fit=crop',
  'Agentes de Voz': 'https://images.unsplash.com/photo-1590602847861-f357a9332bbc?w=1200&auto=format&fit=crop',
  'Integraciones': 'https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=1200&auto=format&fit=crop',
  'Casos de Uso': 'https://images.unsplash.com/photo-1454165804606-c3d57bc86b40?w=1200&auto=format&fit=crop',
  'Noticias IA': 'https://images.unsplash.com/photo-1677442135703-1787eea5ce01?w=1200&auto=format&fit=crop'
};

const photos = pexelsResponse.photos || [];
const isPlaceholder = photos.length === 0 || !photos[0]?.src?.large2x;
let coverImageUrl;

if (!isPlaceholder) {
  coverImageUrl = photos[0].src.large2x;
} else {
  const category = postData.category || 'Automatización';
  coverImageUrl = FALLBACK_IMAGES[category] || FALLBACK_IMAGES['Automatización'];
  console.warn('[IMAGEN PLACEHOLDER] "' + postData.title + '" — categoria: ' + category);
}

return [{ json: { ...postData, coverImageUrl, _imagePlaceholder: isPlaceholder } }];

const response = $input.first().json;
const postData = $('Resolver Imagen Fallback').first().json;
const writerData = $('AI Writer Agent').first().json;

if (response.error) {
  throw new Error('Blog publish network error: ' + JSON.stringify(response.error).substring(0, 300));
}

const status = response.statusCode || response.status || 200;
const responseBody = response.body || response;

if (status >= 200 && status < 300) {
  const usage = writerData.usage || {};
  console.log('[SUCCESS] Publicado: "' + postData.title + '" (' + postData.slug + ')');
  console.log('[TOKENS] input: ' + (usage.input_tokens || '?') + ', output: ' + (usage.output_tokens || '?') + ', total: ' + (usage.total_tokens || '?'));
  console.log('[IMAGE_PLACEHOLDER] ' + (postData._imagePlaceholder ? 'SI — reemplazar antes de indexacion' : 'No'));
  return [{ json: { success: true, status, slug: postData.slug, title: postData.title } }];
}

throw new Error('Blog publish failed ' + status + ': ' + JSON.stringify(responseBody).substring(0, 400));
